def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos2 - pos1)

    def travel_time(from_pos, to_pos):
        distance = euclidean_distance(from_pos, to_pos)
        return distance / truck_speed

    def calculate_dispersion_score(pos, other_trucks_pos):
        # Penalize positions causing trucks to converge towards the same location
        return np.sum([euclidean_distance(pos, other_pos) for other_pos in other_trucks_pos if not np.array_equal(pos, other_pos)])

    def urgency_score(time, window):
        if time < window[0]:
            return (window[0] - time) ** 2
        elif time > window[1]:
            return (time - window[1]) ** 2
        else:
            return 0

    scores = []

    for idx, customer_pos in enumerate(unvisited_customers):
        t_time = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + t_time
        urgency = urgency_score(arrival_time, time_windows[idx])
        dispersion = calculate_dispersion_score(customer_pos, all_truck_pos)

        score = t_time + 10 * urgency - 0.1 * dispersion
        scores.append(score)

    best_node = np.argmin(scores)

    return best_node

