                time_matrix[i, j] = travel_time(truck_positions[i], target_positions[j])
        return time_matrix / np.max(time_matrix)

    def urgency_score(time, window):
        if time < window[0]:
            return window[0] - time
        elif time > window[1]:
            return (time - window[1]) ** 2
        else:
            return 0

    truck_indices = {tuple(pos): idx for idx, pos in enumerate(all_truck_pos)}
    current_truck_index = truck_indices[tuple(cur_truck_pos)]
    normalized_times = calculate_normalized_travel_times(all_truck_pos, unvisited_customers)

    priority_queue = []
    for idx, customer_pos in enumerate(unvisited_customers):
        travel_cost = normalized_times[current_truck_index, idx]
        arrival_time = current_time + (travel_cost * np.max(normalized_times) * truck_speed)
        time_window_urgency = urgency_score(arrival_time, time_windows[idx])

